sql:
SELECT SUM(allocated_amount) AS total_allocated_budget
FROM budget_allocations
WHERE school_id = 0;

SELECT school_name 
FROM schools
ORDER BY school_name;

SELECT school_name 
FROM schools 
ORDER BY school_name ASC;

SELECT school_name
FROM schools
ORDER BY total_budget DESC;

SELECT school_name 
FROM schools 
ORDER BY school_name;

SELECT school_name
FROM schools
ORDER BY school_name;

external_knowledge:
- Academic performance includes average math scores, average reading scores, graduation rates, and dropout rates; 
- Cumulative budget refers to the total amount allocated to each budget category in a school, calculated by summing up the allocated amounts in each category; 
- Demographic breakdowns include the count of students by ethnicity and gender.
